insert into course_semester (
   course_id,
   semester_id
)
   select courses.id,
          7
     from courses
    where courses.kode_matkul = 'SVPL214802';
insert into course_semester (
   course_id,
   semester_id
)
   select courses.id,
          8
     from courses
    where courses.kode_matkul = 'SVPL214802';


-- 1. Bersihkan sisa relasi lama di tabel course_semester (jika ada) untuk menghindari duplikasi
delete from course_semester
 where course_id in (
   select id
     from courses
    where is_pilihan = 'ya'
);

